void setZeroes(vector<vector<int>> &mat) {
    int n = mat.size();
    int m = mat[0].size();
    bool firstColZero = false;

    // First pass: mark rows and columns
    for (int i = 0; i < n; i++) {
        if (mat[i][0] == 0) firstColZero = true;
        for (int j = 1; j < m; j++) {
            if (mat[i][j] == 0) {
                mat[i][0] = 0; // mark row
                mat[0][j] = 0; // mark column
            }
        }
    }

    // Second pass: set zeros using markers (bottom-up)
    for (int i = n - 1; i >= 0; i--) {
        for (int j = m - 1; j >= 1; j--) {
            if (mat[i][0] == 0 || mat[0][j] == 0) {
                mat[i][j] = 0;
            }
        }
        if (firstColZero) {
            mat[i][0] = 0;
        }
    }
}

